class Dog:
    def speak(self):
        return "Woof!"

class Cat:
    def speak(self):
        return "Meow!"

class Duck:
    def speak(self):
        return "Quack!"

dog = Dog()
cat = Cat()
duck = Duck()

print(dog.speak())
print(cat.speak())
print(duck.speak())

animals = [Dog(), Cat(), Duck(), Dog()]

for animal in animals:
    print(animal.speak())

class Robot:
    def speak(self):
        return "Beep boop!"

# Robot has nothing to do with animals, but it has speak()
animals = [Dog(), Cat(), Robot()]

for creature in animals:
    print(creature.speak())

class Animal:
    def speak(self):
        return "..."

class Dog(Animal):
    def speak(self):
        return "Woof!"

class Cat(Animal):
    def speak(self):
        return "Meow!"

class Fish(Animal):
    pass  # Fish doesn't override speak()

animals = [Dog(), Cat(), Fish()]

for animal in animals:
    print(animal.speak())

import math

class Circle:
    def __init__(self, radius):
        self.radius = radius

    def area(self):
        return math.pi * self.radius ** 2

class Rectangle:
    def __init__(self, width, height):
        self.width = width
        self.height = height

    def area(self):
        return self.width * self.height

shapes = [Circle(5), Rectangle(4, 6), Circle(3)]

for shape in shapes:
    print(f"Area: {shape.area():.2f}")

