exercise.solution:
class Trumpet:
    def play(self):
        return "Trumpet goes: Toot toot!"

class Guitar:
    def play(self):
        return "Guitar goes: Strum strum!"

class Piano:
    def play(self):
        return "Piano goes: Plink plink!"

instruments = [Trumpet(), Guitar(), Piano()]

for instrument in instruments:
    print(instrument.play())
